import React from 'react';
import { FlaskConical, Code2, Bug, ArrowRight, Zap } from 'lucide-react';

const features = [
  {
    id: 'testcases',
    icon: FlaskConical,
    color: '#1a56db',
    bg: '#eff6ff',
    border: '#bfdbfe',
    title: 'Test Case Generator',
    desc: 'Generate positive, negative, validation & boundary test cases from module descriptions.',
    actions: ['Import Excel/CSV', 'Export to Excel/CSV', 'Edit & review'],
  },
  {
    id: 'automation',
    icon: Code2,
    color: '#0284c7',
    bg: '#e0f2fe',
    border: '#bae6fd',
    title: 'Automation Scripts',
    desc: 'Convert your test cases into ready-to-run Playwright or Selenium JavaScript scripts.',
    actions: ['Playwright JS', 'Selenium JS', 'Download ZIP'],
  },
  {
    id: 'bugreports',
    icon: Bug,
    color: '#1344b4',
    bg: '#eff6ff',
    border: '#93c5fd',
    title: 'Bug Report Generator',
    desc: 'Create standardized bug reports with severity, priority, and reproduction steps.',
    actions: ['Auto severity', 'Steps to reproduce', 'Structured output'],
  },
];

const stats = [
  { label: 'Manual effort saved', value: '70%+' },
  { label: 'Script gen speed', value: '30s' },
  { label: 'Frameworks', value: '2' },
  { label: 'Export formats', value: '2' },
];

export default function Dashboard({ onNavigate }) {
  return (
    <div>
      {/* Hero */}
      <div style={{
        background: 'linear-gradient(135deg, #1a56db 0%, #3b82f6 100%)',
        borderRadius: 14,
        padding: '28px 30px',
        marginBottom: 24,
        color: 'white',
        boxShadow: '0 6px 20px rgba(26,86,219,0.25)',
        position: 'relative',
        overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', top: -20, right: -20,
          width: 160, height: 160,
          background: 'rgba(255,255,255,0.06)',
          borderRadius: '50%',
        }} />
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 6,
          background: 'rgba(255,255,255,0.2)',
          padding: '4px 12px', borderRadius: 20,
          fontSize: 11, fontWeight: 700, marginBottom: 12,
          backdropFilter: 'blur(4px)',
        }}>
          <Zap size={11} /> AI-POWERED QA PLATFORM
        </div>
        <h1 style={{ color: 'white', fontSize: 26, marginBottom: 8 }}>Welcome to QA Assistant</h1>
        <p style={{ color: 'rgba(255,255,255,0.8)', maxWidth: 500, fontSize: 14 }}>
          Generate test cases, automation scripts, and bug reports in seconds.
          Built for QA engineers who want to move faster.
        </p>
      </div>

      {/* Stats */}
      <div className="stats-row">
        {stats.map(s => (
          <div className="stat-card" key={s.label}>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value">{s.value}</div>
          </div>
        ))}
      </div>

      {/* Feature Cards */}
      <div style={{ display: 'grid', gap: 14 }}>
        {features.map(f => {
          const Icon = f.icon;
          return (
            <div key={f.id} className="card" style={{
              display: 'flex', gap: 18, padding: '18px 22px',
              borderLeft: `4px solid ${f.color}`,
              transition: 'box-shadow 0.15s, transform 0.15s',
              cursor: 'pointer',
            }}
              onClick={() => onNavigate(f.id)}
              onMouseEnter={e => { e.currentTarget.style.boxShadow = '0 4px 16px rgba(26,86,219,0.12)'; e.currentTarget.style.transform = 'translateY(-1px)'; }}
              onMouseLeave={e => { e.currentTarget.style.boxShadow = ''; e.currentTarget.style.transform = ''; }}
            >
              <div style={{
                width: 44, height: 44, borderRadius: 10,
                background: f.bg, border: `1px solid ${f.border}`,
                display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
              }}>
                <Icon size={20} color={f.color} />
              </div>
              <div style={{ flex: 1 }}>
                <h2 style={{ marginBottom: 3 }}>{f.title}</h2>
                <p style={{ color: '#64748b', fontSize: 13, marginBottom: 10 }}>{f.desc}</p>
                <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginBottom: 12 }}>
                  {f.actions.map(a => (
                    <span key={a} style={{
                      fontSize: 11, padding: '2px 8px', borderRadius: 4,
                      background: f.bg, color: f.color,
                      border: `1px solid ${f.border}`, fontWeight: 600,
                    }}>{a}</span>
                  ))}
                </div>
                <button className="btn btn-primary btn-sm" onClick={e => { e.stopPropagation(); onNavigate(f.id); }}>
                  Open {f.title.split(' ')[0]} <ArrowRight size={13} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Phase 2 teaser */}
      <div style={{
        marginTop: 20,
        background: '#0f172a',
        borderRadius: 12,
        padding: '18px 22px',
        display: 'flex',
        alignItems: 'center',
        gap: 14,
        boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
      }}>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: '#3b82f6', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 4 }}>Coming in Phase 2</div>
          <div style={{ color: '#bfdbfe', fontSize: 13, fontWeight: 500 }}>URL & Screenshot-based generation · API test cases · Postman collections</div>
        </div>
        <div style={{ fontSize: 11, color: '#1a56db', background: '#eff6ff', padding: '4px 12px', borderRadius: 20, fontWeight: 700, whiteSpace: 'nowrap' }}>Roadmap →</div>
      </div>
    </div>
  );
}
